// hooks/useQuiz.js
// Custom React hook for fetching quiz questions from /api/quiz/generate
// Handles: loading, error, session cache

import { useState, useCallback, useRef } from "react";

const API_BASE = process.env.REACT_APP_API_URL || "http://localhost:5000";

export function useQuiz() {
  const [loading,   setLoading]   = useState(false);
  const [error,     setError]     = useState(null);
  const clientCache = useRef({});

  const fetchQuiz = useCallback(async (topic, count = 10) => {
    if (!topic) return null;

    const key = `${topic.trim().toLowerCase()}::${count}`;

    if (clientCache.current[key]) {
      return clientCache.current[key];
    }

    setLoading(true);
    setError(null);

    try {
      const res = await fetch(`${API_BASE}/api/quiz/generate`, {
        method:  "POST",
        headers: { "Content-Type": "application/json" },
        body:    JSON.stringify({ topic, count }),
      });

      const json = await res.json();

      if (!res.ok || !json.success) {
        throw new Error(json.details || json.error || `Server error ${res.status}`);
      }

      clientCache.current[key] = json.questions;
      return json.questions;

    } catch (err) {
      setError(err.message);
      return null;
    } finally {
      setLoading(false);
    }
  }, []);

  return { fetchQuiz, loading, error };
}
